// Normaliza cada fila del Sheet al schema de social_posts.
// Salta: INSIGHT, HASHTAGS, SPONSORED (TYPE ya cubre orgánico/pauta).
// Filtra filas sin URL o sin RED-SOCIAL.

const rows = $input.all();

const toInt = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(String(v).replace(/[, ]/g, ''));
  return Number.isFinite(n) ? Math.round(n) : null;
};

const toNum = (v) => {
  if (v === null || v === undefined || v === '') return null;
  // Acepta '0.02%', '0.02', '0,02' → 0.02
  const s = String(v).replace('%', '').replace(',', '.').trim();
  const n = Number(s);
  return Number.isFinite(n) ? n : null;
};

const toDate = (v) => {
  if (!v) return null;
  const s = String(v).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  // DD/M/YYYY o DD/MM/YYYY
  const m = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})/);
  if (m) return `${m[3]}-${m[2].padStart(2,'0')}-${m[1].padStart(2,'0')}`;
  const d = new Date(s);
  return Number.isNaN(d.getTime()) ? null : d.toISOString().slice(0, 10);
};

const output = [];
for (const item of rows) {
  const r = item.json || {};
  const url = (r['POSTEO'] || '').toString().trim();
  const red = (r['RED-SOCIAL'] || '').toString().toUpperCase().trim();
  if (!url || !red) continue;
  output.push({
    red_social:   red,
    url,
    pilar:        (r['PILAR'] || '').toString().trim() || null,
    positivo:     toInt(r['POSITIVO']),
    negativo:     toInt(r['NEGATIVO']),
    neutro:       toInt(r['NEUTRO']),
    likes:        toInt(r['LIKES']),
    comentarios:  toInt(r['COMENTARIOS']),
    engagement:   toNum(r['ENGAGEMENT']),
    fecha:        toDate(r['DATE']),
    tipo:         (r['TYPE'] || '').toString().trim() || null,
    marca:        (r['MARCA'] || '').toString().trim(),
    views:        toInt(r['VIEWS']) || 0,
    content_type: (r['CONTENT_TYPE'] || '').toString().trim() || null,
    followers:    toInt(r['FOLLOWERS']),
  });
}
return output.map(json => ({ json }));
